-- SQL Script to truncate existing tables and seed with new requested data

TRUNCATE TABLE b1 RESTART IDENTITY CASCADE;
TRUNCATE TABLE b2 RESTART IDENTITY CASCADE;
TRUNCATE TABLE b3 RESTART IDENTITY CASCADE;
TRUNCATE TABLE b4 RESTART IDENTITY CASCADE;
TRUNCATE TABLE teachers RESTART IDENTITY CASCADE;

ALTER TABLE teachers ADD COLUMN IF NOT EXISTS subject_code TEXT;
ALTER TABLE teachers ADD COLUMN IF NOT EXISTS subject_name TEXT;
ALTER TABLE teachers ADD COLUMN IF NOT EXISTS teacher_email TEXT;
ALTER TABLE teachers ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();

